export const meta = {
  name: 'qa-workflow-validation-error',
  description: 'QA workflow: how to return error messages for input validation in web app',
  phases: [
    { title: 'Semantic Search', detail: 'Search knowledge files for relevant sections' },
    { title: 'Read Sections', detail: 'Read selected section contents' },
    { title: 'Generate Answer', detail: 'Generate and verify answer' }
  ]
}

phase('Semantic Search')

const searchQuery = '入力チェックでエラーがあったときに、エラーメッセージをユーザーに返す方法を教えてほしい（処理方式: ウェブアプリケーション）（目的: 実装したい）'

const searchResult = await agent(
  `You are executing a semantic search against Nablarch knowledge files.

## Task
Read the semantic search workflow at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/workflows/semantic-search.md

Then execute it with the following query:
"${searchQuery}"

The knowledge files are located at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/

## Output Format
Return a JSON object with:
{
  "selected_sections": [
    {"file": "<full path to knowledge file>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ],
  "selected_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why excluded>"}
  ],
  "excluded_sections": [
    {"file": "<full path>", "section_id": "<sN>", "reason": "<why excluded>"}
  ]
}

Return ONLY the JSON object, no other text.`,
  {
    label: 'semantic-search',
    schema: {
      type: 'object',
      properties: {
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_sections', 'selected_pages', 'excluded_pages', 'excluded_sections']
    }
  }
)

log(`Semantic search complete. Selected ${searchResult.selected_sections.length} sections.`)

phase('Read Sections')

// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')

const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)
const readSectionArgs = sectionsToRead.map(s => {
  // Extract just filename from full path for read-sections.sh
  const parts = s.file.split('/')
  const filename = parts[parts.length - 1]
  return `"${filename}:${s.section_id}"`
}).join(' ')

log(`Reading ${sectionsToRead.length} sections...`)

const sectionsContent = await agent(
  `Execute the following bash command and return the COMPLETE output verbatim:

bash /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh ${readSectionArgs}

The script is located at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh

Working directory should be: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/

Return the COMPLETE raw output of the command, nothing else.`,
  { label: 'read-sections' }
)

log('Sections read. Generating answer...')

phase('Generate Answer')

const answerResult = await agent(
  `You are a Nablarch expert answering a Japanese developer's question.

## Question
入力チェックでエラーがあったときに、エラーメッセージをユーザーに返す方法を教えてほしい（処理方式: ウェブアプリケーション）（目的: 実装したい）

## Section Contents
${sectionsContent}

## Instructions

### Step 5: Generate Answer
Generate a Japanese answer following these steps:
1. Read all sections in section contents.
2. Since processing_type is ウェブアプリケーション, focus on approaches that match that type.
3. Identify the information that directly answers the question. For any gap in the sections, write "この情報は知識ファイルの対象範囲外です" — do not infer.
4. Write the answer in the format below. Stay within 500 tokens (up to 800 for complex questions).

**Answer format**:
**結論**: Direct answer to the question (1–2 sentences)
- Include specific method names, class names, and approaches
- Do not parrot back the question

**根拠**: Code examples, configuration examples, or spec information that backs the conclusion
- Show code/config examples in code blocks
- Priority: implementation example > configuration example > API spec > conceptual explanation
- If using multiple sections, organize along the implementation flow
- Quote code examples from sections verbatim (do not modify)

**注意点**: Constraints, resource management, common mistakes
- Omit this section if nothing applies

参照: Only sections actually cited in the answer (file.json:sN format, omit category path)

### Step 6: Verify Answer
Check that all Nablarch-specific claims in the answer are supported by the section contents.

Extract these claim categories (Nablarch-specific claims):
- API names: e.g., "UniversalDao.deferメソッド", "@InjectForm アノテーション"
- Class names: e.g., "DatabaseRecordReader", "BatchAction"
- Configuration method: e.g., "web-component-configuration.xmlに設定"
- Behavior spec: e.g., "バリデーションエラー時にステータスコード400を返す"
- Constraints: e.g., "Formのプロパティは全てString型"
- Parameters: e.g., "-requestPathで指定", "SQLID"

Do NOT extract as Nablarch-specific:
- General Java: "Beanクラスを作成する", "try-with-resourcesを使う"
- General programming: "バリデーションを実行する", "エラーメッセージを表示する"
- Flow description: "まず〜して、次に〜する"
- General web concepts: "HTTPリクエスト", "JSONレスポンス"

For each extracted claim, judge:
1. Directly stated in section content → supported
2. Direct paraphrase of section content → supported
3. Attribute/behavior/constraint not explicitly stated → unsupported

If any claim is unsupported, set verify_result = FAIL and re-generate answer without those claims.

Return a JSON object:
{
  "answer_text": "<the final verified answer in Japanese markdown>",
  "verify_result": "<PASS|FAIL>",
  "issues": ["<unsupported claim if any>"],
  "used_sections": [{"ref": "<file.json:sN>", "reason": "<why used>"}],
  "unused_sections": [{"ref": "<file.json:sN>", "reason": "<why not used>"}]
}`,
  {
    label: 'generate-answer',
    schema: {
      type: 'object',
      properties: {
        answer_text: { type: 'string' },
        verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
        issues: { type: 'array', items: { type: 'string' } },
        used_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        },
        unused_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        }
      },
      required: ['answer_text', 'verify_result', 'issues', 'used_sections', 'unused_sections']
    }
  }
)

log(`Answer generated. Verify result: ${answerResult.verify_result}`)

return {
  searchResult,
  sectionsToRead,
  answerResult
}

